import React from 'react';
import { Routes, Route, Link, useLocation } from 'react-router-dom';
import { motion } from 'framer-motion';
import { 
  Home, 
  User, 
  Settings, 
  LogOut, 
  Calendar, 
  DollarSign, 
  Users, 
  Package,
  Star,
  TrendingUp,
  FileText,
  MessageSquare,
  Building
} from 'lucide-react';
import { useAuth } from '../../contexts/AuthContext';
import { useLanguage } from '../../contexts/LanguageContext';

// Dashboard Components
const CustomerDashboard = () => {
  const { t } = useLanguage();
  const stats = [
    { title: t('totalOrders'), value: '12', icon: Package, color: 'bg-blue-500' },
    { title: t('pending'), value: '3', icon: Calendar, color: 'bg-yellow-500' },
    { title: t('completed'), value: '9', icon: Star, color: 'bg-green-500' },
    { title: t('totalSpent'), value: 'SGD $2,450', icon: DollarSign, color: 'bg-purple-500' }
  ];

  const recentOrders = [
    { id: 1, service: t('plumbing'), status: t('completed'), date: '2024-01-15', amount: 'SGD $350' },
    { id: 2, service: t('electrical'), status: t('inProgress'), date: '2024-01-18', amount: 'SGD $200' },
    { id: 3, service: t('cleaning'), status: t('pending'), date: '2024-01-20', amount: 'SGD $150' }
  ];

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">{t('customerDashboard')}</h1>
      
      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, index) => (
          <motion.div
            key={index}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: index * 0.1 }}
            className="bg-white p-6 rounded-lg shadow-md"
          >
            <div className="flex items-center">
              <div className={`p-3 rounded-full ${stat.color} text-white`}>
                <stat.icon size={24} />
              </div>
              <div className="ml-4">
                <p className="text-sm text-gray-600">{stat.title}</p>
                <p className="text-2xl font-bold">{stat.value}</p>
              </div>
            </div>
          </motion.div>
        ))}
      </div>

      {/* Recent Orders */}
      <div className="bg-white rounded-lg shadow-md p-6">
        <h2 className="text-xl font-semibold mb-4">{t('recentOrders')}</h2>
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b">
                <th className="text-left py-3">{t('service')}</th>
                <th className="text-left py-3">{t('status')}</th>
                <th className="text-left py-3">{t('date')}</th>
                <th className="text-left py-3">{t('amount')}</th>
                <th className="text-left py-3">{t('actions')}</th>
              </tr>
            </thead>
            <tbody>
              {recentOrders.map((order) => (
                <tr key={order.id} className="border-b hover:bg-gray-50">
                  <td className="py-3">{order.service}</td>
                  <td className="py-3">
                    <span className={`px-2 py-1 rounded-full text-xs ${
                      order.status === t('completed') ? 'bg-green-100 text-green-800' :
                      order.status === t('inProgress') ? 'bg-blue-100 text-blue-800' :
                      'bg-yellow-100 text-yellow-800'
                    }`}>
                      {order.status}
                    </span>
                  </td>
                  <td className="py-3">{order.date}</td>
                  <td className="py-3">{order.amount}</td>
                  <td className="py-3">
                    <button className="text-blue-600 hover:underline">{t('viewDetails')}</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

const VendorDashboard = () => {
  const { t } = useLanguage();
  const stats = [
    { title: t('totalIncome'), value: 'SGD $15,680', icon: DollarSign, color: 'bg-green-500' },
    { title: t('monthlyOrders'), value: '28', icon: Package, color: 'bg-blue-500' },
    { title: t('customerRating'), value: '4.8', icon: Star, color: 'bg-yellow-500' },
    { title: t('activeCustomers'), value: '45', icon: Users, color: 'bg-purple-500' }
  ];

  const recentJobs = [
    { id: 1, customer: t('mrZhang'), service: t('plumbing'), status: t('inProgress'), amount: 'SGD $350' },
    { id: 2, customer: t('msLi'), service: t('electrical'), status: t('completed'), amount: 'SGD $200' },
    { id: 3, customer: t('mrWang'), service: t('cleaning'), status: t('pending'), amount: 'SGD $150' }
  ];

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">{t('vendorDashboard')}</h1>
      
      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, index) => (
          <motion.div
            key={index}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: index * 0.1 }}
            className="bg-white p-6 rounded-lg shadow-md"
          >
            <div className="flex items-center">
              <div className={`p-3 rounded-full ${stat.color} text-white`}>
                <stat.icon size={24} />
              </div>
              <div className="ml-4">
                <p className="text-sm text-gray-600">{stat.title}</p>
                <p className="text-2xl font-bold">{stat.value}</p>
              </div>
            </div>
          </motion.div>
        ))}
      </div>

      {/* Recent Jobs */}
      <div className="bg-white rounded-lg shadow-md p-6">
        <h2 className="text-xl font-semibold mb-4">{t('recentJobs')}</h2>
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b">
                <th className="text-left py-3">{t('customer')}</th>
                <th className="text-left py-3">{t('service')}</th>
                <th className="text-left py-3">{t('status')}</th>
                <th className="text-left py-3">{t('amount')}</th>
                <th className="text-left py-3">{t('actions')}</th>
              </tr>
            </thead>
            <tbody>
              {recentJobs.map((job) => (
                <tr key={job.id} className="border-b hover:bg-gray-50">
                  <td className="py-3">{job.customer}</td>
                  <td className="py-3">{job.service}</td>
                  <td className="py-3">
                    <span className={`px-2 py-1 rounded-full text-xs ${
                      job.status === t('completed') ? 'bg-green-100 text-green-800' :
                      job.status === t('inProgress') ? 'bg-blue-100 text-blue-800' :
                      'bg-yellow-100 text-yellow-800'
                    }`}>
                      {job.status}
                    </span>
                  </td>
                  <td className="py-3">{job.amount}</td>
                  <td className="py-3">
                    <button className="text-blue-600 hover:underline">{t('viewDetails')}</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

const AdminDashboard = () => {
  const { t } = useLanguage();
  const stats = [
    { title: t('totalUsers'), value: '1,234', icon: Users, color: 'bg-blue-500' },
    { title: t('totalVendors'), value: '89', icon: Building, color: 'bg-green-500' },
    { title: t('monthlyIncome'), value: 'SGD $45,680', icon: DollarSign, color: 'bg-purple-500' },
    { title: t('pendingApproval'), value: '12', icon: FileText, color: 'bg-yellow-500' }
  ];

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">{t('adminDashboard')}</h1>
      
      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, index) => (
          <motion.div
            key={index}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: index * 0.1 }}
            className="bg-white p-6 rounded-lg shadow-md"
          >
            <div className="flex items-center">
              <div className={`p-3 rounded-full ${stat.color} text-white`}>
                <stat.icon size={24} />
              </div>
              <div className="ml-4">
                <p className="text-sm text-gray-600">{stat.title}</p>
                <p className="text-2xl font-bold">{stat.value}</p>
              </div>
            </div>
          </motion.div>
        ))}
      </div>

      {/* Quick Actions */}
      <div className="grid md:grid-cols-2 gap-6">
        <div className="bg-white rounded-lg shadow-md p-6">
          <h2 className="text-xl font-semibold mb-4">{t('quickActions')}</h2>
          <div className="space-y-3">
            <button className="w-full text-left p-3 border rounded-lg hover:bg-gray-50">
              {t('approveVendorApplications')}
            </button>
            <button className="w-full text-left p-3 border rounded-lg hover:bg-gray-50">
              {t('viewSystemReports')}
            </button>
            <button className="w-full text-left p-3 border rounded-lg hover:bg-gray-50">
              {t('manageUserAccounts')}
            </button>
          </div>
        </div>

        <div className="bg-white rounded-lg shadow-md p-6">
          <h2 className="text-xl font-semibold mb-4">{t('systemStatus')}</h2>
          <div className="space-y-3">
            <div className="flex justify-between">
              <span>{t('serverStatus')}</span>
              <span className="text-green-600">{t('normal')}</span>
            </div>
            <div className="flex justify-between">
              <span>{t('databaseConnection')}</span>
              <span className="text-green-600">{t('normal')}</span>
            </div>
            <div className="flex justify-between">
              <span>{t('paymentSystem')}</span>
              <span className="text-green-600">{t('normal')}</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const DashboardPage = () => {
  const { user, logout } = useAuth();
  const location = useLocation();
  const { t } = useLanguage();

  const navigation = [
    { name: t('dashboard'), href: '/dashboard', icon: Home },
    { name: t('profile'), href: '/dashboard/profile', icon: User },
    { name: t('settings'), href: '/dashboard/settings', icon: Settings }
  ];

  const handleLogout = () => {
    logout();
  };

  // 根据用户角色显示不同的仪表盘
  const getDashboardContent = () => {
    if (!user) return <div>{t('pleaseLogin')}</div>;
    
    switch (user.role) {
      case 'customer':
        return <CustomerDashboard />;
      case 'vendor':
        return <VendorDashboard />;
      case 'admin':
        return <AdminDashboard />;
      default:
        return <CustomerDashboard />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="flex">
        {/* Sidebar */}
        <div className="w-64 bg-white shadow-lg min-h-screen">
          <div className="p-6">
            <h1 className="text-xl font-bold text-gray-900 mb-6">{t('swiftFixPro')}</h1>
            
            <nav className="space-y-2">
              {navigation.map((item) => {
                const isActive = location.pathname === item.href;
                return (
                  <Link
                    key={item.name}
                    to={item.href}
                    className={`flex items-center px-4 py-2 rounded-lg transition-colors ${
                      isActive
                        ? 'bg-blue-100 text-blue-700'
                        : 'text-gray-600 hover:bg-gray-100'
                    }`}
                  >
                    <item.icon size={20} className="mr-3" />
                    {item.name}
                  </Link>
                );
              })}
            </nav>

            <div className="mt-8 pt-6 border-t">
              <button
                onClick={handleLogout}
                className="flex items-center px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg w-full"
              >
                <LogOut size={20} className="mr-3" />
                {t('logout')}
              </button>
            </div>
          </div>
        </div>

        {/* Main Content */}
        <div className="flex-1 p-8">
          <Routes>
            <Route path="/" element={getDashboardContent()} />
            <Route path="/profile" element={<div>{t('profilePage')}</div>} />
            <Route path="/settings" element={<div>{t('settingsPage')}</div>} />
          </Routes>
        </div>
      </div>
    </div>
  );
};

export default DashboardPage;
